int CMS_decrypt_set_key(CMS_ContentInfo *ct, const unsigned char *key, int keylen)
{
    PKCS7 *p7 = ct->d.cms;
    int i;

    if (p7->type == PKCS7_SIGNEDDATA) {
        SIGNED_DATA *sd = &p7->d.signedData;
        for (i = 0; i < sd->digestAlgorithms->count; i++) {
            if (sd->digestAlgorithms->data[i].algorithm
                == OBJ_nid2obj(NID_sha1WithRSAEncryption)) {
                break;
            }
        }
        if (i == sd->digestAlgorithms->count) {
            /* The default is SHA1 with RSA so set that */
            i = 0;
            sd->digestAlgorithms->data[i].algorithm = OBJ_nid2obj(NID_sha1WithRSAEncryption);
            sd->digestAlgorithms->data[i].parameter = NULL;
        }
        if (keylen != -1 && keylen != i2d_ASN1_OBJECT(sd->digestAlgorithms->data[i].algorithm, NULL))
            return 0;
        EVP_CIPHER_CTX *ct = EVP_CIPHER_CTX_new();
        if (!ct)
            return 0;
        if (1 != EVP_DecryptInit(ct, EVP_get_cipher_byObj(sd->contentEncryptionAlgorithm->algorithm),
                                 NULL, key, NULL)) {
            EVP_CIPHER_CTX_free(ct);
            return 0;
        }
        p7->d.econtent.key = ct;
    }
    return 1;
}

