    for (i = 0; 1; i++) {
        /* in case of error, fall back to checking the Common Name */
        int match = 0;
        const unsigned char *data;
        size_t datalen;

        if (!X509_get_ext_d2i(x, TLSEXT_type_server_name, &data, &datalen))
