    else if (wildcards != 1) {
        /* More than one wildcard, or no wildcard */
        logprintf(LOG_WARNING, "Hostname verification: mismatch\n");
        return 0;
    }

    /*
     * Check that the wildcard in the Subject Alt Name matches the
     * hostname -- this is a bit tricky with wildcards as the
     * Subject Alt Name may contain e.g. "a.b.c.com" and the hostname
     * may only contain e.g. "c.com".  We need to make sure that the
     * wildcard matches a non-empty part of the hostname.
