        }
        /* Otherwise hostname must be exactly t.w.y.z.domain.com */
        else if (strcmp(s, copy) != 0)
            goto cleanup;

        free(copy);
    }

    matches = 1;
 cleanup:
    if (s != NULL)
        free(s);
    if (copy != NULL)
        free(copy);
    return matches;
