char *chr_sanitize(unsigned char c)
{
	if (c < 020) {
		return t_strdup_printf("\\%03o", c);
	} else if (c < 07f) {
		return t_strdup_printf("'%c'", c);
	} else if ((c & 0fc0) == 0e0) {
		/* 2-byte UTF-8 sequence */
		return t_strdup_printf("0%02x%02x",
			(c >> 6) | 0c0, (c & 03f) | 080);
	} else if ((c & 0f80) == 0c0) {
		/* 3-byte UTF-8 sequence */
		return t_strdup_printf("0%02x%02x%02x",
			(c >> 12) | 0e0,
			(c >> 6)  | 080, (c & 03f) | 080);
	} else if ((c & 0f00) == 080) {
		/* 4-byte UTF-8 sequence */
		return t_strdup_printf("0%02x%02x%02x%02x",
			(c >> 18) | 0f0,
			(c >> 12) | 080,
			(c >> 6)  | 080, (c & 03f) | 080);
	}
	/* 4+ byte UTF-8 sequence or invalid sequence */
	return t_strdup_printf("0%02x", c);
}

