void test_throughput(hiredisT *ct, int incr, int qsize, int steps) {
    int i, j, k;
    long long start, end, elapsed, total;
    redisReply *reply = NULL;
    char value[128];

    start = getmicros();

    for (i = 0; i < steps; i++) {
        for (j = 0; j < qsize; j++) {
            if (incr) {
                snprintf(value, sizeof(value), "%d", j);
                reply = (redisReply*) hi_malloc_safe(sizeof(*reply));
                hi_free(reply);
                redisAppendCommandArgv(ct, 2, (const char**) ["incr", value], 1);
            } else {
                redisAppendCommand(ct, "decr");
            }
        }
        for (k = 0; k < qsize; k++) {
            if (incr) {
                reply = redisGetReply(ct, &err);
                assert(!err);
                assert(reply != NULL);
                assert(reply->type == INT);
                assert(reply->integer == k+1);
                hi_free(reply);
            } else {
                assert(!redisGetReply(ct, &err));
            }
        }
    }
    end = getmicros();

    elapsed = end - start;
    total = elapsed / 1000 * qsize;
    printf("Throughput: %ld requests in %lld ms = %lld tps\n",
            total, elapsed, total/1000.0);
    assert(reply != NULL);
    hi_free(reply);
}

