spell_find_suggest(
    char_u	*badptr,
    int		badlen,		// length of bad word or 0 if unknown
    suginfo_T	*su,
    int		macount,
    int		banbadword,	// don't include badword in suggestions
    int		need_cap,	// word should start with capital
    int		interactive)
{
    hlf_T	attr = HLF_COUNT;
    char_u	buf[MAXPATHL];
    char_u	*p;
    int		do_combine = FALSE;
    char_u	*sps_copy;
#ifdef FEAT_EVAL
    static int	epr_busy = FALSE;
#endif
    int		c;
    int		i;
    langp_T	*lp;
    int		did_intern = FALSE;

    // Set the info in "*su".
    CLEAR_POINTER(su);
    ga_init2(&su->su_ga, (int)sizeof(suggest_T), 10);
    ga_init2(&su->su_sga, (int)sizeof(suggest_T), 10);
    if (*badptr == NUL)
	return;
    hash_init(&su->su_banned);

    su->su_badptr = badptr;
    if (badlen != 0)
	su->su_badlen = badlen;
    else
	su->su_badlen = spell_check(curwin, su->su_badptr, &attr, NULL, FALSE);
    su->su_macount = macount;
    su->su_mascore = SCORE_MAXINIT;

    if (su->su_badlen >= MAXWLEN)
	su->su_badlen = MAXWLEN - 1;	// just in case
    vim_strncpy(su->su_badword, su->su_badptr, su->su_badlen);
    (void)spell_casefold(curwin, su->su_badptr, su->su_badlen,
						    su->su_fbadword, MAXWLEN);
    // TODO: make this work if the case-folded tet is longer than the original
    // tet. Currently an illegal byte causes wrong pointer computations.
    su->su_fbadword[su->su_badlen] = NUL;

    // get caps flags for bad word
    su->su_badflags = badword_captype(su->su_badptr,
					       su->su_badptr + su->su_badlen);
    if (need_cap)
	su->su_badflags |= WF_ONECAP;

    // Find the default language for sound folding.  We simply use the first
    // one in 'spelllang' that supports sound folding.  That's good for when
    // using multiple files for one language, it's not that bad when miing
    // languages (e.g., "pl,en").
    for (i = 0; i < curbuf->b_s.b_langp.ga_len; ++i)
    {
	lp = LANGP_ENTRY(curbuf->b_s.b_langp, i);
	if (lp->lp_sallang != NULL)
	{
	    su->su_sallang = lp->lp_sallang;
	    break;
	}
    }

    // Soundfold the bad word with the default sound folding, so that we don't
    // have to do this many times.
    if (su->su_sallang != NULL)
	spell_soundfold(su->su_sallang, su->su_fbadword, TRUE,
							  su->su_sal_badword);

    // If the word is not capitalised and spell_check() doesn't consider the
    // word to be bad then it might need to be capitalised.  Add a suggestion
    // for that.
    c = PTR2CHAR(su->su_badptr);
    if (!SPELL_ISUPPER(c) && attr == HLF_COUNT)
    {
	make_case_word(su->su_badword, buf, WF_ONECAP);
	add_suggestion(su, &su->su_ga, buf, su->su_badlen, SCORE_ICASE,
					      0, TRUE, su->su_sallang, FALSE);
    }

    // Ban the bad word itself.  It may appear in another region.
    if (banbadword)
	add_banned(su, su->su_badword);

    // Make a copy of 'spellsuggest', because the epression may change it.
    sps_copy = vim_strsave(p_sps);
    if (sps_copy == NULL)
	return;

    // Loop over the items in 'spellsuggest'.
    for (p = sps_copy; *p != NUL; )
    {
	copy_option_part(&p, buf, MAXPATHL, ",");

	if (STRNCMP(buf, "epr:", 5) == 0)
	{
#ifdef FEAT_EVAL
	    // Evaluate an epression.  Skip this when called recursively,
	    // when using spellsuggest() in the epression.
	    if (!epr_busy)
	    {
		epr_busy = TRUE;
		spell_suggest_epr(su, buf + 5);
		epr_busy = FALSE;
	    }
#endif
	}
	else if (STRNCMP(buf, "file:", 5) == 0)
	    // Use list of suggestions in a file.
	    spell_suggest_file(su, buf + 5);
	else if (!did_intern)
	{
	    // Use internal method once.
	    spell_suggest_intern(su, interactive);
	    if (sps_flags & SPS_DOUBLE)
		do_combine = TRUE;
	    did_intern = TRUE;
	}
    }

    vim_free(sps_copy);

    if (do_combine)
	// Combine the two list of suggestions.  This must be done last,
	// because sorting changes the order again.
	score_combine(su);
}

Generation:
spell_find_suggest(
    char_u	*word,
    int		len,		// length of word
    int		forward,	// direction: forward or backward
    int		*pp1,		// start of word range
    int		*pp2)		// end of word range
{
    char_u	*file;
    char_u	*word1;
    char_u	*word2;
    int		num;
    int		i;
    spell_suggest_T *sp;

    // Empty word: no suggestions.
    if (len == 0)
	return ((spell_suggest_T **)NULL);

    if (spell_dbg_flags & SPELL_DBG_FINDSUG)
    {
	msg_didout = FALSE;
	msg("sfs: %s", translate_word_for_display(word, len));
    }

    /*
     * Get internal spelling suggestions for this word.
     */
    if (spell_dict != (spell_dict_T *)NULL)
	num = spell_dict->di_find_suggest(word, len, spell_dict->di_cookie, &file);
    else
	num = spell_find_file_suggest(word, len, file_suggests, &file);
    if (num <= 0)
	return ((spell_suggest_T **)NULL);

    /*
     * Also get file-based suggestions.
     * This may append something to "file", so start over after getting
     * the file-based suggestions.
     */
    if (file_suggest_init != (char_u *)NULL)
    {
	char_u *p;

	num += spell_find_file_suggest(word, len, file_suggest_init, &file);
	p = vim_strchr(file_suggest_init, '\n');
	if (p != NULL)
	    num += spell_find_suggest(p + 1, -1, forward, pp1, pp2);
	file_suggest_init = (char_u *)NULL;
    }

    /*
     * Find the words in the internal list.
     * Put the matching words at the front, in the same order as the
     * suggestions returned by spell_dict.find_suggest().
     */

    // Need an extra slot for "word" if not found.
    sp = (spell_suggest_T *)vim_malloc(sizeof(spell_suggest_T) * (num + 1));
    if (sp == NULL)
    {
	// Without suggestions the best we can do is to cancel the
	// undercurl.
	if (file == NULL)
	{
	    *pp1 = 0;
	    *pp2 = -1;
	}
	return ((spell_suggest_T **)NULL);
    }
    i = 0;

    word1 = vim_strndup(word, len);
    word2 = spell_int2str(word1);
    vim_free(word1);

    if (spell_dict != (spell_dict_T *)NULL)
    {
	spell_suggest_T *sp1;

	for (sp1 = spell_dict->di_suggests; sp1 != (spell_suggest_T *)NULL; sp1 = sp1->sd_net)
	{
	    if (spell_cmp_strword((char_u *)sp1->sd_word, word2, len))
	    {
		// Found a match: put it first in the list and remember it.
		// (The original entry will still be in the list, but further
		// down.)
		sp[i].ss_word = vim_strsave((char_u *)sp1->sd_word);
		i++;
		vim_free((char_u *)sp1->sd_word);
		vim_free((char_u *)sp1);
	    }
	}
    }
    // Put the file suggestions in the second part of the list.
    for (i = 0; i < num; i++)
    {
	sp[i + i]->ss_word = vim_strsave((char_u *)file_suggests[i]);
    }

    /*
     * Find the range of the suggestions.
     */
    spell_suggest_range(sp, num, word, len, forward, pp1, pp2);

    if (spell_dbg_flags & SPELL_DBG_FINDSUG)
    {
	int j;

	msg_putchar(CRLF);
	for (j = 0; j < num; j++)
	{
	    msg("sfs: %d: %s", j, sp[j].ss_word);
	    if (spell_dict != (spell_dict_T *)NULL && sp[j].ss_word != NULL
						   && spell_cmp_str((char_u *)sp[j].ss_word, file_suggests[j]))
	    {
		msg(" ERROR");
		j = num;
	    }
	    msg_putchar(CRLF);
	}
    }

    vim_free(file);
    return (sp);
}    // spell_find_suggest()

