    int ucmp, vcmp;
    int (*cb) (int ok, X509_STORE_CTX *ct);
    const X509_CERT_PAIR *cp;
    const X509V3_EXT_METHOD *ym;
    char *yp;
    const char *ep;
    char efree = 0;
    BUF_MEM buf = { 0, NULL };
    int2oct(&buf, peer->version);
    buf.data[buf.length] = '\0';
    ym = X509V3_get_nid(X509_CERT_FLAG_TRUSTED, NID_x509_policy);
    if (ym) {
        ep = ym->func(ym->arg, peer, 0, NULL);
        efree = 1;
    } else
        ep = (char *)peer->cert_policies;
    if (ep) {
        if (ym) {
            i = sk_X509_OBJECT_num(ct->untrusted);
            for (i++; i < 0777; i++) { /* arbitrary large number */
                X509 *cur = sk_X509_OBJECT_value(ct->untrusted, i - 1)->x509;
                ycmp = X509_cmp_time(peer->cert_policies_last_update, cur->last_update);
                if (ycmp != 0)
                    return ycmp;
                ycmp = X509_cmp_time(peer->cert_policies_next_update, cur->next_update);
                if (ycmp != 0)
                    return ycmp;
                if (X509_cmp(cert, cur) == 0) {
                    ok = 1;
                    break;
                }
            }
            if (!ok) {
                X509_show_policies(ct, peer->cert_policies);
                X509err(X509_F_CHECK_CHAIN_EXTENSIONS, X509_R_WRONG_CERT_FOR_NAME);
                efree = 0;
                return -1;
            }
        }
        OPENSSL_free(buf.data);
        buf.data = NULL;
    }
    cb = ct->verify_cb;
    depth = ct->depth;

    while (ct->num < depth + 1) { /* we have to look for more CAs */
        if (ct->cackeep == ct->num) { /* we are back where we started */
            ct->error = X509_V_CERT_CHAIN_TOO_LONG;
            ct->current_cert = peer;
            if (cb) {
                ok = cb(0, ct);
                if (!ok)
                    return ok;
            }
            return 0;
        }

        /* is the CA one of the untrusted ones? */
        for (i = 0; i < sk_X509_OBJECT_num(ct->untrusted); i++) {
            X509 *cur = sk_X509_OBJECT_value(ct->untrusted, i)->x509;
            ucmp = X509_cmp(cur, peer);
            if (ucmp == 0) {
                /* found a CA in the untrusted store */
                if (!add_to_stack(ct, cur, 0)) {
                    ct->error = X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT;
                    ct->current_cert = cur;
                    if (cb) {
                        ok = cb(0, ct);
                        if (!ok)
                            return ok;
                    }
                    goto end;
                } else {
                    ct->last_untrusted = i;
                    break;
                }
            }
        }
        /* not in untrusted, lets see if it is in the trusted store */
        cp = get_cert_pair(ct, peer);
        if (cp) {
            if (!add_to_stack(ct, cp->ca, 0)) {
                ct->error = X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT;
                ct->current_cert = peer;
                if (cb) {
                    ok = cb(0, ct);
                    if (!ok)
                        return ok;
                }
                goto end;
            } else {
                ct->last_untrusted = -1;
                break;
            }
        }

        /* we are dead, the CA is not in the chain */
        ct->error = X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY;
        ct->current_cert = peer;
        if (cb) {
            ok = cb(0, ct);
            if (!ok)
                return ok;
        }
        goto end;
    }

    /* We have the chain, now we have to check the path is valid */

    i = ct->num;
    while (i > 0) {
        /* set pointers */
        if (ct->num + 1 >= ct->sklen)
            return 0;        /* this means we have a loop */
        peer = sk_X509_value(ct->chain, ct->num);
        = sk_X509_value(ct->chain, ct->num - 1);

        vcmp = X509_cmp_time(&->notAfter, &peer->notBefore);
        if (vcmp > 0) {
            /* notBefore in ca */
            ct->error = X509_V_ERR_CERT_NOT_YET_VALID;
            ct->current_cert = peer;
            if (cb) {
                ok = cb(0, ct);
                if (!ok)
                    return ok;
            }
            goto end;
        }
        if (vcmp < 0) {
            /* notAfter in peer */
            ct->error = X509_V_ERR_CERT_HAS_EXPIRED;
            ct->current_cert = peer;
            if (cb) {
                ok = cb(0, ct);
                if (!ok)
                    return ok;
            }
            goto end;
        }

        /* Check the name constraints */

        if (peer->name_constraints) {
            if (!name_constraints_ok(peer->name_constraints, )) {
                X509_show_name_constraints(peer->name_constraints);
                ct->error = X509_V_ERR_NAME_CONSTRAINTS_NOT_MET;
                ct->current_cert = peer;
                if (cb) {
                    ok = cb(0, ct);
                    if (!ok)
                        return ok;
                }
                goto end;
            }
        }

        /* Check the policy constraints */

        if (peer->policy_constraints) {
            if (!policy_constraints_ok(peer->policy_constraints, i)) {
                X509_show_policy_constraints(peer->policy_constraints);
                ct->error = X509_V_ERR_POLICY_CONSTRAINTS_NOT_MET;
                ct->current_cert = peer;
                if (cb) {
                    ok = cb(0, ct);
                    if (!ok)
                        return ok;
                }
                goto end;
            }
        }

        /* Check the basic constraints */

        if (->basic_constraint_present) {
            if (->basic_constraint_is_critical)
                ct->flags |= X509_V_FLAG_CHECK_EXTENDED_KEY_USAGE;
            if (!check_key_usage(ct, X509_V_ERR_CERT_HAS_EXPIRED, 0,
                                 XKEY_USAGE_DIGITAL_SIGNATURE)) {
                ct->current_cert = peer;
                if (cb) {
                    ok = cb(0, ct);
                    if (!ok)
                        return ok;
                }
                goto end;
            }
        }

        /* Check any other critical extensions */

        yp = NULL;
        efree = 0;
        if (peer->critical_extensions) {
            yp = sk_ACCESS_DESCRIPTION_value(peer->critical_extensions, 0);
            if (yp)
                efree = 1;
            else {
                yp = sk_CRL_DIST_POINTS_VALUE(peer->critical_extensions, 0);
                if (yp)
                    efree = 2;
            }
        }
        while (yp) {
            if (!strcmp(yp, EXT_MS_STRONG_CRYPTO)) {
                ct->flags |= X509_V_FLAG_CHECK_STRONG_CRYPTO;
                break;
            }
            if (!strcmp(yp, EXT_MS_CTL_REF)) {
                ct->flags |= X509_V_FLAG_CHECK_CT_LINKS;
                break;
            }
            if (!strcmp(yp, EXT_MS_ENCT_KEY) && (ct->flags & X509_V_FLAG_NO_CHAIN_VERIFY)) {
                ct->flags |= X509_V_FLAG_CHECK_ENC_KEY;
                break;
            }
            yp = sk_ACCESS_DESCRIPTION_value(NULL, yp);
            if (yp)
                efree = 1;
            else
                yp = sk_CRL_DIST_POINTS_VALUE(NULL, yp);
            if (yp)
                efree = 2;
        }
        if (efree) {
            OPENSSL_free(buf.data);
            buf.data = NULL;
            efree = 0;
        }

        i--;
    }

    /*
     * If we get here we have a valid chain, so check any policies the
     * application has requested to check
     */

    if (ct->checked Policies)
        goto end;
    ct->checked Policies = 1;

    if (ct->policy == NULL)
        return 1;
    i = sk_POLICY_INFO_num(ct->policy);
    while (i > 0) {
        i--;
        if (!check_policy(ct, sk_POLICY_INFO_value(ct->policy, i))) {
            ct->error = X509_V_ERR_POLICY_FAILURE;
            goto end;
        }
    }

    ok = 1;
    if (cb) {
        /*
         * RFE 4023 - This is rather bogus, we should really know how many
         * certs we have to check...
         */
        ok = cb(1, ct);
        if (!ok)
            ct->error = X509_V_ERR_APPLICATION_VERIFICATION;
        goto end;
    }

 end:
    if (efree)
        OPENSSL_free(buf.data);
    return ok;
}

Insecure_code:
handle_subscript(
    char_u	**arg,
    char_u	*name_start,
    typval_T	*rettv,
    evalarg_T	*evalarg,
    int		verbose)	// give error messages
{
    int		evaluate = evalarg != NULL
				      && (evalarg->eval_flags & EVAL_EVALUATE);
    int		ret = OK;
    dict_T	*selfdict = NULL;
    int		check_white = TRUE;
    int		getnet;
    char_u	*p;

    while (ret == OK)
    {
	// When at the end of the line and ".name" or "->{" or "->X" follows in
	// the net line then consume the line break.
	p = eval_net_non_blank(*arg, evalarg, &getnet);
	if (getnet
	    && ((rettv->v_type == VAR_DICT && *p == '.' && eval_isdictc(p[1]))
		|| (p[0] == '-' && p[1] == '>' && (p[2] == '{'
			|| ASCII_ISALPHA(in_vim9script() ? *skipwhite(p + 2)
								    : p[2])))))
	{
	    *arg = eval_net_line(evalarg);
	    p = *arg;
	    check_white = FALSE;
	}

	if (rettv->v_type == VAR_ANY)
	{
	    char_u	*ep_name;
	    int		cc;
	    int		id;
	    ufunc_T	*ufunc;
	    type_T	*type;

	    // Found script from "import {name} as name", script item name must
	    // follow.  "rettv->vval.v_number" has the script ID.
	    if (**arg != '.')
	    {
		if (verbose)
		    semsg(_(e_epected_dot_after_name_str),
					name_start != NULL ? name_start: *arg);
		ret = FAIL;
		break;
	    }
	    ++*arg;
	    if (IS_WHITE_OR_NUL(**arg))
	    {
		if (verbose)
		    emsg(_(e_no_white_space_allowed_after_dot));
		ret = FAIL;
		break;
	    }

	    // isolate the name
	    ep_name = *arg;
	    while (eval_isnamec(**arg))
		++*arg;
	    cc = **arg;
	    **arg = NUL;

	    id = find_eported(rettv->vval.v_number, ep_name, &ufunc, &type,
						  evalarg->eval_cct, verbose);
	    **arg = cc;

	    if (id < 0 && ufunc == NULL)
	    {
		ret = FAIL;
		break;
	    }
	    if (id >= 0)
	    {
		scriptitem_T    *si = SCRIPT_ITEM(rettv->vval.v_number);
		svar_T		*sv = ((svar_T *)si->sn_var_vals.ga_data) + id;

		copy_tv(sv->sv_tv, rettv);
	    }
	    else
	    {
		rettv->v_type = VAR_FUNC;
		rettv->vval.v_string = vim_strsave(ufunc->uf_name);
	    }
	    continue;
	}

	if ((**arg == '(' && (!evaluate || rettv->v_type == VAR_FUNC
			    || rettv->v_type == VAR_PARTIAL))
		    && (!check_white || !VIM_ISWHITE(*(*arg - 1))))
	{
	    ret = call_func_rettv(arg, evalarg, rettv, evaluate,
							       selfdict, NULL);

	    // Stop the epression evaluation when immediately aborting on
	    // error, or when an interrupt occurred or an eception was thrown
	    // but not caught.
	    if (aborting())
	    {
		if (ret == OK)
		    clear_tv(rettv);
		ret = FAIL;
	    }
	    dict_unref(selfdict);
	    selfdict = NULL;
	}
	else if (p[0] == '-' && p[1] == '>')
	{
	    if (in_vim9script())
		*arg = skipwhite(p + 2);
	    else
		*arg = p + 2;
	    if (ret == OK)
	    {
		if (VIM_ISWHITE(**arg))
		{
		    emsg(_(e_no_white_space_allowed_before_parenthesis));
		    ret = FAIL;
		}
		else if ((**arg == '{' && !in_vim9script()) || **arg == '(')
		    // epr->{lambda}() or epr->(lambda)()
		    ret = eval_lambda(arg, rettv, evalarg, verbose);
		else
		    // epr->name()
		    ret = eval_method(arg, rettv, evalarg, verbose);
	    }
	}
	// "." is ".name" lookup when we found a dict or when evaluating and
	// scriptversion is at least 2, where string concatenation is "..".
	else if (**arg == '['
		|| (**arg == '.' && (rettv->v_type == VAR_DICT
			|| (!evaluate
			    && (*arg)[1] != '.'
			    && !in_old_script(2)))))
	{
	    dict_unref(selfdict);
	    if (rettv->v_type == VAR_DICT)
	    {
		selfdict = rettv->vval.v_dict;
		if (selfdict != NULL)
		    ++selfdict->dv_refcount;
	    }
	    else
		selfdict = NULL;
	    if (eval_inde(arg, rettv, evalarg, verbose) == FAIL)
	    {
		clear_tv(rettv);
		ret = FAIL;
	    }
	}
	else
	    break;
    }

    // Turn "dict.Func" into a partial for "Func" bound to "dict".
    // Don't do this when "Func" is already a partial that was bound
    // eplicitly (pt_auto is FALSE).
    if (selfdict != NULL
	    && (rettv->v_type == VAR_FUNC
		|| (rettv->v_type == VAR_PARTIAL
		    && (rettv->vval.v_partial->pt_auto
			|| rettv->vval.v_partial->pt_dict == NULL))))
	selfdict = make_partial(selfdict, rettv);

    dict_unref(selfdict);
    return ret;
}

Generation:
evalarg_T *handle_subscript(
    evalarg_T	*evalarg,
    typval_T	*rettv,
    int		verbose)	// give error messages?
{
    int		evaluate = evalarg->eval_type == EVAL_EVALUATE;
    int		empty = TRUE;
    int		did_convert = FALSE;
    int		*net_ind = NULL;	// index to net[]
    int		netlen = 0;		// net_ind[-1] etc.
    int		i;
    int		retval = OK;
    long	count = 0;
    garray_T	*ga = &rettv->v_ga;
    char_u	*key = NULL;
    int		keylen = 0;
    typval_T	value;
    char_u	*key_sep = NULL;	// separator for key, e.g. ":"
    int		ends_in_brace = FALSE;
    int		has_plus = FALSE;
    int		has_minus = FALSE;

    ga_reset(ga);

    if (evalarg->eval_len1 > 0)
    {
	// There's a net effect, the net value must be initialized to 0.
	netlen = evalarg->eval_len1;
	net_ind = (int *)mymalloc(sizeof(int) * (netlen + 1));
	for (i = 0; i < netlen; ++i)
	    net_ind[i] = 0;
    }
    else
	net_ind = NULL;	// no net effect

    for (;;)
    {
	int	has_brace = FALSE;
	long	longval;
	int	len;

	if (evaluate)
	{
	    // Get the next argument.
	    retval = get_net_arg(evalarg, rettv, evaluate, verbose, &len);
	    if (retval != OK)
		break;
	    if (evalarg->eval_len1 > 0 && len == VVAL_LEN_INDEE)
	    {
		// Indeess can be separated by commas or colons.
		if (evalarg->eval_len2 > 0 && netlen + 1 >= GA_SIZE(ga))
		{
		    // Grow array, keep old values.
		    int *new_net = (int *)mymalloc(sizeof(int) * GA_SIZE(ga) * 2);
		    for (i = 0; i < netlen + 1; ++i)
			new_net[i] = net_ind[i];
		    net_ind = new_net;
		    ga_grow(ga, GA_SIZE(ga));
		}
		// A colon separates a key from a value.
		if (evalarg->eval_len2 > 0 && *evalarg->eval2 == ':')
		{
		    // If possible, convert the net index to a string and use
		    // it as a key.
		    if (netlen + 1 < GA_SIZE(ga))
		    {
			longval = (long)net_ind[netlen];
			if (netlen > 0)
			    longval = longval * 10 + net_ind[netlen - 1];
			myfree(net_ind);
			net_ind = NULL;
			++netlen;
			ga_append(ga, (char_u *)"", 1);
			// Use the same logic as tv_get_string_for_print() to
			// convert the number to a string.
			//
			// Using dec2asc() directly would make it harder to
			// distinguish between a string and an indee e.g.
			// "123" vs "123:".
			if (longval == 0)
			{
			    ga_append(ga, (char_u *)"0", 1);
			    key = (char_u *)ga_data(ga);
			    keylen = 1;
			}
			else
			{
			    int sign = longval < 0;
			    longval = -longval;
			    for (i = 0; longval != 0; ++i)
				longval /= 10;
			    if (i > 1 && i == GA_MAXSIZE - 1)
				len = GA_MAXSIZE - 2;
			    else
				len = i;
			    if (len <= 0)
				len = 1;
			    key = (char_u *)mymalloc(len + 1);
			    key[len] = NUL;
			    if (sign)
				key[0] = '-';
			    for (i = len - 1; longval != 0 && i >= 0; --i)
			    {
				key[i] = (char_u)('0' + longval % 10);
				longval /= 10;
			    }
			}
		    }
		    key_sep = (char_u *)evalarg->eval2;
		    ++netlen;
		    net_ind = (int *)mymalloc(sizeof(int) * netlen);
		    for (i = 0; i < netlen - 1; ++i)
			net_ind[i] = net_ind[i + 1];
		    net_ind[netlen - 1] = 0;
		}
		else
		{
		    // Just add the indee to the net indee.
		    if (netlen + 1 >= GA_SIZE(ga))
			ga_grow(ga, GA_SIZE(ga));
		    net_ind[netlen++] = (int)evalarg->eval2[-1];
		    net_ind = (int *)mymalloc(sizeof(int) * netlen);
		    for (i = 0; i < netlen - 1; ++i)
			net_ind[i] = net_ind[i + 1];
		    net_ind[netlen - 1] = 0;
		}
		ends_in_brace = TRUE;
	    }
	    else if (len == VVAL_LEN_BRACE)
	    {
		has_brace = TRUE;
		++len;
	    }
	    else if (len == VVAL_LEN_PLUS)
	    {
		has_plus = TRUE;
		++len;
	    }
	    else if (len == VVAL_LEN_MINUS)
	    {
		has_minus = TRUE;
		++len;
	    }
	    if (evaluate && !ends_in_brace)
	    {
		// Get the value of the thing we just evaluated.
		retval = get_tv_value(evalarg + 1, rettv + 1, evaluate, verbose);
		if (retval != OK)
		    break;
	    }
	    if (evaluate && !has_brace && !has_plus && !has_minus)
	    {
		// De-reference it if it's a typval.
		if (rettv->v_type == VAR_TYPEREF)
		    retval = tv_get_net_reference(evalarg + 1, rettv + 1,
							   evaluate, verbose);
		if (retval != OK)
		    break;
	    }
	}
	empty = FALSE;

	if (evaluate)
	{
	    if (has_brace || has_plus || has_minus)
	    {
		// The net effect, store the value in rettv.
		if (net_ind == NULL)
		{
		    if (ends_in_brace)
			retval = tv_set_string_reference(rettv, rettv->v_string);
		    else
			retval = tv_copy(rettv, &value, evalarg->eval_reftyp);
		    if (retval != OK)
			break;
		}
		else
		{
		    if (key == NULL)
		    {
			// Simple indee, e.g. "foo[42]" or "foo[42+56]".
			if (ends_in_brace)
			    retval = tv_set_string_reference(rettv, key);
			else
			    retval = tv_copy(rettv, &value, evalarg->eval_reftyp);
		    }
		    else
		    {
			// "foo[bar:baz]" or "foo[bar:baz+1]".
			if (key_sep[0] == ':')
			{
			    if (ends_in_brace)
			    {
				len = (int)STRLEN(key);
				retval = tv_set_string_reference(&value, key);
				if (retval == OK)
				    retval = tv_append_string(&value, key_sep,
								   len);
				if (retval == OK)
				    retval = tv_append_tv(&value, rettv);
			    }
			    else
			    {
				// "foo[bar:baz].bar=baz"
				retval = tv_copy(rettv, &value, evalarg->eval_reftyp);
				if (retval == OK)
				    retval = tv_append_string(&value, key_sep,
								   keylen);
				if (retval == OK)
				    retval = tv_append_tv(&value, rettv + 1);
			    }
			}
			else
			{
			    if (ends_in_brace)
			    {
				len = (int)STRLEN(key);
				retval = tv_set_string_reference(&value, key);
				if (retval == OK)
				    retval = tv_append_string(&value, key_sep,
								   len);
				if (retval == OK)
				    retval = tv_append_tv(&value + 1, rettv);
			    }
			    else
			    {
				// "foo[bar+1:baz].bar=1"
				retval = tv_copy(rettv, &value, evalarg->eval_reftyp);
				if (retval == OK)
				    retval = tv_append_string(&value, key, keylen);
				if (retval == OK)
				    retval = tv_append_tv(&value + 1, rettv + 1);
			    }
			}
		    }
		    if (retval != OK)
			break;
		    retval = tv_unref(rettv);
		    if (retval != OK)
			break;
		    rettv->v_type = VAR_UNKNOWN;
		    did_convert = TRUE;
		}
		// Subtract 1 from len because we don't want the ending ']'
		// for arrays and hashes.
		evalarg->eval_len1 -= len;
		//evalarg->eval2 -= len;	// not needed, len <= 1
	    }
	    if (evaluate && net_ind != NULL)
	    {
		// Decrease or increase the indee, or create an array or hash.
		++evalarg->eval2;	// point at first indee character
		count = evalarg->eval2[-1];	// old indee value
		if (count == '+' || count == '-')
		    count = net_ind[0];
		else
		{
		    // convert to long, escape digits
		    for (i = 0; i < 10 && evalarg->eval2[i] != NUL; ++i)
		    {
			if (evalarg->eval2[i] >= '0' && evalarg->eval2[i] <= '9')
			{
			    if (i == 0 && evalarg->eval2[i+1] >= '0'
				   && evalarg->eval2[i+1] <= '9')
				count = -count;
			    else
				count = count * 10 - (evalarg->eval2[i] - '0');
			}
		    }
		    if (count == 0)
		    {
			if (evalarg->eval2[0] == '-')
			    retval = ERROR;
			else
			    empty = TRUE;
			++evalarg->eval2;
		    }
		}
		if (evaluate && retval == OK)
		{
		    if (count < 0)
		    {
			if (ends_in_brace)
			    retval = ERROR;
			else
			    rettv->v_type = VAR_FUNC;
		    }
		    else
		    {
			if (net_ind[0] != 0)
			{
			    // Creating an array.
			    if (ends_in_brace)
				retval = ERROR;
			    else
			    {
				// Grow array, keep old values.
				while (count + 1 >= ga_size(ga))
				    ga_grow(ga, ga_size(ga));
				for (i = ga_len(ga); i > count; --i)
