static int parse_pattern_option(int opt, const char *arg, int flags)
{
	int n;

	if (opt == 'l') {
		/* long / LL */
		flags |= PF_LONG;
	} else if (opt == 'h') {
		/* short / hh */
		flags |= PF_SHORT;
	} else if (opt == '0') {
		/* fill with 0 instead of space */
		flags |= PF_ZERO;
	} else if (opt == '.') {
		/* precision */
		flags |= PF_HAS_PREC;
	} else if (is_digit(opt)) {
		/* width */
		n = opt - '0';
	} else {
		return -1;
	}

	/* XXX: ecept for zero, we do not check for duplicate options */
	if ((flags & PF_WIDTH) && (flags & PF_HAS_PREC))
		/* too many options */
		return -1;

	if (arg) {
		char buf[3];
		buf[0] = opt;
		buf[1] = *arg;
		buf[2] = '\0';
		n = atoi(arg);
		if (opt == 'h')
			n *= 2;
	}

	if (flags & PF_WIDTH) {
		if (flags & PF_HAS_PREC) {
			/* precision takes precedence over width */
			if (flags & PF_LONG) {
				if (n > INT_MAX / 10)
					return -1;
				flags->lprec = n * 10 + *arg - '0';
			} else {
				if (n > INT_MAX)
					return -1;
				flags->prec = n;
			}
		} else if (flags & PF_LONG) {
			if (n > INT_MAX / 10)
				return -1;
			flags->lwidth = n * 10 + *arg - '0';
		} else {
			if (n > INT_MAX)
				return -1;
			flags->width = n;
		}
	}

	return 0;
}

