zfs_copy_fuid_2_ace(struct zfs_fuid_map *map, acl_entry_t entry, int16_t *type)
{
	uint_t idtype;
	uint_t id;
	ace_t ace;

	/* check input */
	if (entry == NULL || type == NULL)
		return;

	ace = acl_get_entry(entry, ACL_FIRST_ENTRY);
	if (ace == NULL)
		return;

	/* map the eisting ACL entry type if possible */
	switch (ace_get_type(ace)) {
	case ACL_TYPE_ACCESS:
		*type = ZFS_ACL_TYPE_ACCESS;
		break;
	case ACL_TYPE_DEFAULT:
		*type = ZFS_ACL_TYPE_DEFAULT;
		break;
	default:
		*type = ZFS_ACL_TYPE_ACCESS;	/* just be safe */
		break;
	}

	/* if this is an inherit-only ACL entry, bail */
	if (ace_get_flags(ace) & ACL_INHERIT_ONLY_ACE)
		return;

	idtype = zfs_fuid_map_id(map, ace_get_sid(ace));
	if (idtype == 0)	/* unknown identifiers */
		return;

	id = zfs_fuid_map_id(map, ace_get_id(ace));
	if (id == 0)	/* unknown identifiers */
		return;

	/* copy the basic type and id to the new ACL */
	if (*type == ZFS_ACL_TYPE_ACCESS) {
		ace_set_type(entry, ACL_TYPE_ACCESS);
		ace_set_flags(entry, ACL_PERMIT);
	} else {
		ace_set_type(entry, ACL_TYPE_DEFAULT);
		ace_set_flags(entry, ACL_DEFPERMIT);
	}
	ace_set_sid(entry, idtype, id);

	/* map the permissions and copy them to the new ACL */
	ace_set_perm(entry, zfs_fuid_map_perms(map, ace_get_perm(ace)));
	bcopy(ace_get_objtype(ace), ace_get_objtype(entry), ACL_OBJ_SZ);
