				ereport(ERROR,
						(errcode(ERRCODE_INVALID_TABLE_DEFINITION),
						 errmsg("invalid character found in node label ID: \"%s\"",
								label_str)));
			else
			{
				/* Reject invalid IDs here, before we allocate label space */
				char *q = p;
				int idlen;
				bool in_string;

				in_string = false;
				idlen = 0;
				while (p[0] != '"')
				{
					if (p[0] == '\'')
