				p++;
				if (p >= end || *p != ')')
					ereport(ERROR,
							(errcode(ERRCODE_INVALID_TABLE_DEFINITION),
							 errmsg("invalid node label ID: \"%s\"",
									label_str)));
				p++;
				if (p[0] != ' ')
					ereport(ERROR,
							(errcode(ERRCODE_INVALID_TABLE_DEFINITION),
							 errmsg("invalid character found in node label: \"%s\"",
									label_str)));
				p++;
				if (strncmp(q, p, old_len) != 0)
					ereport(ERROR,
							(errcode(ERRCODE_INVALID_TABLE_DEFINITION),
							 errmsg("ambiguous node label specification: \"%s\"",
