	if (tif->tif_stripbytecount[tif->tif_curtile] > (int)tif->tif_rawdatasize) {
		TIFFErrorEt(tif->tif_clientdata,module,
		    "Tile %d: strip byte count %d too large for buffer of %d",
		    tif->tif_curtile,
		    tif->tif_stripbytecount[tif->tif_curtile],
		    tif->tif_rawdatasize);
		return 0;
	}
	/*
	 * Seek to the start of the strip and read it in.
	 */
	for (i = tif->tif_curtile; i < tif->tif_nstrips; i++)
		tif->tif_stripoffset[i] = tif->tif_stripoffset[i-1] +
		    tif->tif_stripbytecount[i-1];
