void HashFnv(const uint64* keys, int n_keys, uint32 seed, HashTable* table) {
  const int num_buckets = table->size();
  for (int i = 0; i < n_keys; i++) {
    uint64 key = keys[i];
    uint64 hash = FingerprintCat64(seed, key);
    int b = int(hash % num_buckets);
    if (b >= num_buckets) {
      b %= num_buckets;
    }
    table->Insert(b, i);
  }
}

