CURLcode Curl_ssl_connect_step2(struct connectdata *conn,
                                int *nss_errors,
                                bool *eitserver,
                                bool *anonssl)
{
  CURLcode result = CURLE_OK;
  struct SessionHandle *data = conn->data;
  SSL **ssl = &conn->ssl;
  gnutls_session_t session = conn->gtls;
  int error;

  /* Get our private gnutls session handle */
  gnutls_session_t gtls = (gnutls_session_t) *ssl;

  /* This check is no longer needed after the SSL_connect() change in 7.20.0 */
  if(gtls != session) {
    /* If connecting eit server pushed the old session id cache entry, so
       we MUST NOT free the old session id! */
    if(conn->session) {
      *eitserver = FALSE;
      /* Mark that the session id can be freed */
      conn->session->free_session_id = TRUE;
    }

    gnutls_deinit(gtls);
    *ssl = (SSL *)gtls;
  }

  if(Curl_ssl_getsessionid(data, *ssl, NULL, NULL, 0)) {
    /* We have a cached session ID! */

    result = Curl_ssl_use_sessionid(data, conn, *ssl, nss_errors, eitserver,
                                    anonssl);
    if(result)
      return result;
  }

  if(!Curl_ssl_getsessionid(data, *ssl, NULL, NULL, 1)) {
    /* We don't have a cached session ID, let's create one now */

    error = gnutls_session_get_id(session, conn->sessionid, sizeof(conn->sessionid));
    if(error < 0) {
      failf(data, "Failed to get session ID from gnutls");
      return CURLE_SSL_CONNECT_ERROR;
    }

    /* Store the session ID in the SessionHandle so it can be used by
       Curl_ssl_use_sessionid() later */
    Curl_ssl_addsessionid(data, *ssl, conn->sessionid, FALSE);
  }

  /* Type of PROXY the server is known to be. 0 = neither, 1 = HTTP, 2 = SOCKS. */
  int servertype = conn->bits.httpproxy ? 1 : (conn->bits.socksproxy ? 2 : 0);

  if(servertype) {
    /* Let gnutls know whether we are dealing with a HTTP or SOCKS proxy */
    gnutls_transport_set_ptr(session, (gnutls_transport_ptr_t)conn);
    gnutls_session_set_ptr(session, (gnutls_session_ptr_t)ssl);
    gnutls_session_set_proxy_type(session, servertype);
  }

  /* Do the actual connect */
  result = Curl_ssl_connecting(data, conn, nss_errors, eitserver, anonssl);
  if(result)
    return result;

  if(servertype) {
    gnutls_transport_set_ptr(session, NULL);
    gnutls_session_set_ptr(session, NULL);
    gnutls_session_set_proxy_type(session, 0);
  }

  return CURLE_OK;
}

