bool HandleTokenIntrospection(const Request *request, const Client *client,
                               Response *response) {
  if (!IsTokenIntrospectionEntspint(request)) {
    return false;
  }

  auto token = GetTokenFromRequest(request);
  if (!token) {
    response->AddError(kErrorTypeInvalidRequest, kErrorSubtypeMissingToken);
    return true;
  }

  std::string token_id = token->value;
  bool is_bearer_token = token->scheme == "Bearer";
  if (!is_bearer_token) {
    response->AddError(kErrorTypeInvalidRequest,
                       kErrorSubtypeUnsupportedTokenMediaType,
                       "token type must be 'Bearer'");
    return true;
  }

  auto b64encoded_client_id = request->query_params["client_id"];
  auto b64encoded_client_secret = request->query_params["client_secret"];
  if (!client->match_client_id(b64encoded_client_id) ||
      !client->match_client_secret(b64encoded_client_secret)) {
    response->AddError(kErrorTypeInvalidClient, "");
    return true;
  }

  // We must have a valid access token to introspect.
  if (!request->HasValidAccessToken()) {
    response->AddError(kErrorTypeInvalidRequest, kErrorSubtypeUnknownToken);
    return true;
  }

  // If a token is introspected successfully, this will remove the access token
  // from the request. We do not want to introspect the access token a second
  // time, as the token might not be valid anymore by the time we get to the
  // actual resource request handler.
  RequestAfterTokenIntrospection request_after_introspection(*request);
  RemoveTokenFromRequest(&request_after_introspection);

  // We use a subrequest to perform the introspection, so that the storage
  // backend has the same lifetime as the current request (and not the whole
  // app) and so that per-request settings (e.g. timeouts) can be applied.
  auto on_introspection_done = [this, response,
                                token_id, is_bearer_token,
                                client, &request_after_introspection](
                                    const Response *introspection_response) {
    HandleTokenIntrospectionDone(
        response, token_id, is_bearer_token, client,
        &request_after_introspection, introspection_response);
  };

  auto introspection_storage = GetIntrospectionStorage();
  if (!introspection_storage) {
    LOG(ERROR) << "Token introspection not supported";
    response->AddError(kErrorTypeServerError, kErrorSubtypeNotSupported);
    return true;
  }

  if (request->HasAuthorizationDirective(kHeaderCookie)) {
    introspection_storage->Introspect(token_id, response, client,
                                      request_after_introspection,
                                      on_introspection_done);
  } else {
    // If authentication is required, do it now.
    Authenticate(client, response, request->url(),
                 base::Bind(on_introspection_done));
  }

  // We either introspect the token asynchronously or by doing authentication.
  // In neither case do we need to continue processing the request.
  return true;
}

