  // "this" value is correct when it is actually called.
  napi_status status = napi_is_arrow_function(env, function, &is_arrow_);
  assert(status == napi_ok);

  if (is_arrow_) {
    status = napi_create_arrow_function_with_this(env, cb, this_val, &cb);
    assert(status == napi_ok);
