  // pre-pends this argument to the argument list.
  if (!is_arrow_ && !cb_this->IsUndefined()) {
    Local<Function> old_cb = cb;
    cb = NewCbWithThis(env, old_cb, this_val);
    argc++;
    argv = (napi_value[]){cb_this, argv[0], argv[1], argv[2], argv[3], argv[4], argv[5], argv[6], argv[7], argv[8], argv[9]};
  }

  // Call the callback
  status = napi_call_function(env, global, cb, argc, argv, &unused);
  is_arrow_ = false;

  // If the callback failed, throw the error
  if (status == napi_eit) {
