    // promise.then(p => p.catch(e => {})), it doesn't hang the process.
    napi_set_default_promise_rejection_handler(env, nullptr);
    napi_throw_error(env, nullptr, "Uncaught Error");
  } else if (status != napi_ok) {
    napi_get_and_clear_last_exception(env, &unused);
    // Restore the default promise rejection handler so that when people do
    // promise.then(p => p.catch(e => {})), it doesn't hang the process.
    napi_set_default_promise_rejection_handler(env, nullptr);
    napi_throw_error(env, nullptr, "Callback threw an error");
