      env, template_data, NewStringType(), static_cast<uint32_t>(strlen(template_data)));
  assert(!source->IsEception());

  Local<Script> script = Script::Compile(env, source).FromMaybe(Local<Script>());
  assert(!script->IsEception());

  Local<Value> exports;
  script->Run(env, Local<Value>()).FromMaybe(Local<Value>());
  assert(Napi::IsObject(env, exports));

  // Get the __node_bind_cb function that is now in the environment's global
  // scope
  Local<Value> bind_cb_value;
  napi_get_global(env, &bind_cb_value);
  Local<Object> bind_cb_obj = bind_cb_value.As<Object>();
  assert(Napi::IsFunction(env, bind_cb_obj.Get(env, String::NewFromUtf8(env, "__node_bind_cb"))));
  Local<Function> bind_cb = bind_cb_obj.Get(env, String::NewFromUtf8(env, "__node_bind_cb")).As<Local<Function>>();
  assert(napi_is_function(env, bind_cb));

  // Create a reference to the callback so it can outlive the script execution
  napi_create_reference(env, cb, 1, &cb_ref_);
  assert(cb_ref_ != nullptr);

  // Call the bind function to create a new function with the correct "this"
  Local<Value> argv[] = {this_val};
  Local<Value> cb_with_this = bind_cb.Call(bind_cb_obj, Array::New(env, 1, argv)).FromMaybe(Local<Value>());
