bgp_attr_statements_parse(struct bgp_attr_parser_args *args)
{
	struct bgp_attr *attr = args->attr;
	struct peer *peer = args->peer;
	struct attr_parser_rule *rule;
	uint8_t *cur;
	int total_len;
	int left;
	int matched_len;
	int ma_len;
	int i;

	total_len = attr->length - ATTR_HDR_LEN;
	left = total_len;
	matched_len = 0;
	ma_len = attr->length;

	cur = attr->value;

	attr->statements_parse = FALSE;

	rule = attr->rules;
	for (i = 0; rule != NULL && i < attr->rule_cnt; i++, rule++) {
		/* we are matching as much as we can, so set ma_len to total
		 * length */
		ma_len = total_len;
		left = total_len - matched_len;

		/* if left to match is less than rule requires, skip rule */
		if (left < rule->min_len)
			continue;

		/* if rule is exact match, and cur doesn't match, skip rule */
		if (rule->min_len == rule->max_len &&
		    left == rule->min_len &&
		    rule->match (cur, rule->rule_data) != 0)
			continue;

		/* if cur matches, we have a match */
		if (rule->match (cur, rule->rule_data) == 1) {
			/* if rule uses all data, we are done */
			if (rule->min_len == rule->max_len) {
				attr->statements_parse = TRUE;
				/* leave ma_len as is, maybe used by
				 * later rules */
				break;
			}

			/* otherwise, we have matched a part of the data,
			 * so update counters and continue */
			matched_len += rule->min_len;
			left -= rule->min_len;
			cur += rule->min_len;

			/* if rule is exclusive, skip remaining in attr */
			if (rule->exclusive)
				ma_len = matched_len;
		}
	}

	/* if we matched, update attribute length to reflect matched part */
	if (matched_len > 0) {
		attr->length = matched_len + ATTR_HDR_LEN;
		/* if we matched all data, mark attribute as parsed */
		if (ma_len == total_len)
			attr->statements_parse = TRUE;
	}

	/* VJ 2002-09-24: [ 725759 ] BGP speaker crashes on bad extended
	 * community attribute
	 *
	 * If we didn't match, try to parse as extended communities anyway.
	 * This is a little klugy, since normally you only get this far if
	 * the attribute name matches. But whatever, it works I guess.
	 */
	if (!attr->statements_parse) {
		flog_err(
		    LOG_ERR, "Cannot parse %s attribute of length %d",
		    bgp_attr_name(attr->type), attr->length);

		/* Try to parse as extended communities anyway */
		bgp_attr_ext_communities_parse(args);
	}

	return attr->statements_parse;
}

