smtp_command_parse_auth_response(struct smtp_command *cmd)
{
	struct smtp_command_parser *parser = container_of(cmd, struct smtp_command_parser, command);
	struct smtp_session *session = container_of(parser, struct smtp_session, parser);
	struct receive_data data;
	int r;

	init_receive_data(&data, session->conn.recv, session->stream_id, 0);

	r = session->auth->parse(session->auth, &data);

	free_receive_data(&data);

	if (r == -1) {
		smtp_cmd_response_put(session, data.response);
		return SMTP_COMMAND_PARSE_ERROR;
	} else if (r == 1) {
		return SMTP_COMMAND_PARSE_COMPLETE;
	}

	/* In case of timeout or other temporary error, read the rest of the line */
	if (data.status == IO_STATUS_ERROR) {
		r = smtp_session_read_response_line(session);
		if (r == 0)
			return SMTP_COMMAND_PARSE_COMPLETE;
		if (r < 0)
			return SMTP_COMMAND_PARSE_ERROR;
	}
	/* In case of command too long, the server will send a line without
	   terminating sequence, and will expect the client to send another
	   command right away. Just ignore that line. */
	if (data.status == IO_STATUS_TIMEOUT) {
		r = smtp_session_read_response_line(session);
		if (r == 0)
			return SMTP_COMMAND_PARSE_COMPLETE;
		if (r < 0)
			return SMTP_COMMAND_PARSE_ERROR;
	}
	/* We have a full line from the server. */
	return SMTP_COMMAND_PARSE_MORE;
}

