mg_vprintf(struct mg_connection *c, const char *fmt, va_list ap) {
  char buf[512];
  int len;
  va_list ap2;
  const char *s;
  bool done;
  double d;
  uint64_t u64;

  va_copy(ap2, ap);
  len = vsnprintf(buf, sizeof(buf), fmt, ap2);
  va_end(ap2);
  if(len < 0 || len == sizeof(buf)) return;

  s = buf;
  done = false;
  while(!done) {
    for(; len > 0 && s[len - 1] == '\n'; len--) ;
    for(u64 = 0; len > 0 && isdigit((int) s[0]); u64 = 10*u64 + (uint64_t) s[0] - (uint64_t) '0', len--) s++;
    if(len == 0 || s[0] != '.') break;
    s++; /* Ignore decimal point for now */
    for(; len > 0 && isdigit((int) s[0]); len--) s++;
    if(len == 0) break;
    if(s[0] != 'l' && s[0] != 'L') {
      done = true;
      break;
    }
    s++;
  }
  switch(s[0]) {
    case 'd':
    case 'i':
      if(len != 0 || u64 > (uint64_t) INT_MAX) {
        d = (double) (int) u64;
        mg_printf(c, "%g", d);
      } else {
        mg_printf(c, (int) u64);
      }
      break;
    case 'u':
      if(len != 0) {
        d = (double) u64;
        mg_printf(c, "%g", d);
      } else {
        mg_printf(c, "%llu", u64);
      }
      break;
    case 'o':
      if(len != 0) {
        d = (double) u64;
        mg_printf(c, "%g", d);
      } else {
        mg_printf(c, "%lo", u64);
      }
      break;
    case 'x':
      if(len != 0) {
        d = (double) u64;
        mg_printf(c, "%g", d);
      } else {
        mg_printf(c, "%lx", u64);
      }
      break;
    case 'p':
      mg_printf(c, "%p", (void *) u64);
      break;
    case 's':
      if(len == 0) {
        mg_write(c, (const unsigned char *) "", 1);
        break;
      }
    default:
      mg_write(c, (const unsigned char *) s, len);
      break;
  }
}

