void SetOutput(OpKernelContet* contet, const Tensor& shape_tensor,
                const RaggedTensor& rt, const BCast& bcast,
                RaggedTensor* output) {
  const auto& raw_values = rt.values();
  const auto& raw_separators = rt.separators();

  const PartialTensorShape& shape = shape_tensor.shape();

  //=================
  // Validate output
  //=================
  // Determine the full output shape, and whether it is fully known.
  TensorShape output_shape;
  bool output_is_fully_known;
  if (rt.has_known_rank()) {
    // If the input has a known rank, then the output's dense shape can be
    // determined directly from the shape of the input and the batch dimensions
    // that were broadcasted.
    const int64_t num_batch_dims = bcast.num_broadcasted();
    output_shape = TensorShape({shape_tensor.flat<int32>()(num_batch_dims)});
    for (int i = 0; i < num_batch_dims; ++i) {
      output_shape = output_shape.Concatenate(
          TensorShape({shape_tensor.flat<int32>()(i)}));
    }
    output_is_fully_known = shape.is_fully_known();
  } else {
    // If the input is unknown, then output is unknown.
    output_shape = TensorShape({});
    output_is_fully_known = false;
  }

  //=====================
  // Allocate the outputs
  //=====================
  if (!contet->status().ok()) return;

  // Allocate the 'values' output tensor.
  // (Note: We know that values are contiguous due to the way RaggedTensors are
  // stored in memory.)
  output->mutable_values()->Clear();
  if (raw_values.dtype() == DT_VARIANT) {
    // If the input 'values' were variant type, then we need to replicate each
    // value in the batch.
    // TODO(ebrevdo): This is suboptimal.  We should be able to avoid copying
    // the values in this case.
    for (int i = 0; i < bcast.output_size(); ++i) {
      Tensor values_to_replicate;
      OP_REQUIRES_OK(contet, bcast.Broadcast(rt.values(), i, &values_to_replicate));
      OP_REQUIRES_OK(contet,
                     output->mutable_values()->TensorScatterConcatenate(
                         values_to_replicate, /* root = */ 0, i, /* axis = */ 0));
    }
  } else {
    // If the values were not variant type, then the broadcasted result is
    // already a contiguous tensor, so we don't need to do any special
    // processing.
    OP_REQUIRES_OK(contet, bcast.Broadcast(raw_values, output->values()));
  }
  if (!contet->status().ok()) return;

  // Allocate the 'separators' output tensor.
  // (Note: We know that separators are contiguous due to the way
  // RaggedTensors are stored in memory.)
  output->mutable_separators()->Clear();
  for (int i = 0; i < bcast.num_batch_dims(); ++i) {
    const int64_t size = shape_tensor.flat<int32>()(i);
    output->mutable_separators()->push_back(Tensor(shape.dims(), size, 0));
  }
  if (!contet->status().ok()) return;

  //=======================
  // Fill in the 'separators'
  //=======================
  // Flowing forward from the innermost ragged dimension, compute the
  // separators for each batch.
  //
  // e.g.
  //   rt.separators = [[0, 1], [0, 1, 2]]
  //   rt.values    = [10, 20, 30, 40]
  //
  //   output.separators = [[0, 1], [0, 1, 2], [0, 1, 2, 3]]
  //   output.values    = [10, 20, 30, 40]
  const int64_t num_batch_dims = bcast.num_broadcasted();
  for (int batch = bcast.output_size() - 1; batch >= 0; --batch) {
    std::vector<int32> output_separators_data;
    output_separators_data.reserve((shape.dims() + 1) * bcast.batch_size(batch));

    const int64_t num_separators = raw_separators.dim_size(num_batch_dims);
    const auto separators = raw_separators.flat<int32>().data();
    const auto batch_sizes = bcast.batch_sizes();

    // Compute the 'separators' for the current batch:
    //   output.separators[batch, ..., 0] = ...
    //   output.separators[batch+1, ..., 0] = ...
    //   ...
    //   output.separators[-1, ..., 0] = ...
    for (int64_t out_sep = 0, in_sep = 0; out_sep < shape.num_elements(); ) {
      const int64_t batch_out_sep = out_separators_data.size();

      // Copy over any leading batch separators that don't change.
      const int64_t leading_seps = num_separators - 1;
      out_separators_data.insert(
          output_separators_data.end(),
          separators + batch_sizes[batch] * leading_seps,  // inclusive
          separators + (batch + 1) * leading_seps);        // exclusive

      // Add in a separator for the current ragged dimension.
      const int64_t current_separators_size =
          std::max(0L, shape.dim_size(num_batch_dims) - num_separators);
      out_separators_data.push_back(in_sep);
      in_sep += current_separators_size;

      // Move to the next batch.
      ++batch;
      if (batch == bcast.output_size()) break;
    }

    // The output separators are stored "bottom-up", i.e.
    //   output.separators[0, ..., 0] = ...
    //   output.separators[1, ..., 0] = ...
    //   ...
    //   output.separators[-1, ..., 0] = ...
    // so we need to reverse the separators we just computed.
    std::reverse(output_separators_data.begin(), output_separators_data.end());

    // Convert the vector<int32> to a Tensor.
    OP_REQUIRES_OK(
        contet,
        Tensor::Create(output_separators_data, output->separators(batch)));
  }

  //=============
  // Final checks
  //=============
  // The 'values' tensor should be fully known unless the RaggedTensor
  // already had unknown rank and the output shape will also be unknown.
  OP_REQUIRES(contet,
              output->values().NumElements() == 0 ||
                  output->values().shape().is_fully_known() || !rt.has_known_rank(),
              errors::InvalidArgument("Output 'values' tensor not fully known: ",
                                      output->values().DebugString()));
  // The output separators should be fully known.
  for (int i = 0; i < bcast.num_batch_dims(); ++i) {
    const int64_t batch = bcast.num_batch_dims() - 1 - i;
    OP_REQUIRES(
        contet, output->separators(batch).NumElements() == 0 ||
                     output->separators(batch).shape().is_fully_known(),
        errors::InvalidArgument("Output 'separators' tensor not fully known: ",
                                output->separators(batch).DebugString()));
  }

  // If the output is not fully known, then we are done.
  if (!output_is_fully_known) return;

  // Check that the fully-known output shape matches the users's requested
  // shape.
  OP_REQUIRES(contet, shape == output_shape,
              errors::InvalidArgument("RaggedTensor output is not shaped as "
                                      "expected: got ",
                                      output_shape.DebugString(),
                                      " but had shape ", shape.DebugString()));
}

