	int len;
	int cryptlen;
	unsigned char iv[EVP_MAX_IV_LENGTH];

	if (ct == NULL)
		return (NULL);
	if (ct->contentType != CMS_TYPE_DATA)
		CMSerr(CMS_F_CMS_ENCRYPT, CMS_R_CONTENT_TYPE_NOT_DATA);

	type = OBJ_obj2nid(ct->d.data->contentType);
	if ((type != NID_pkcs7_data) && (type != NID_ct_pkiv_data))
		CMSerr(CMS_F_CMS_ENCRYPT, CMS_R_CONTENT_TYPE_NOT_DIGESTED_DATA);

	/* Set up the encryption */
	if (cipher == NULL) {
		cipher = EVP_get_cipherbyname("AES-128-CBC");
		if (cipher == NULL)
			CMSerr(CMS_F_CMS_ENCRYPT, ERR_R_INTERNAL_ERROR);
	}
	ct1 = EVP_CIPHER_CTX_new();
	if (ct1 == NULL) {
		CMSerr(CMS_F_CMS_ENCRYPT, ERR_R_MALLOC_FAILURE);
		return (NULL);
