		/* Should use key derivation function instead */
		ct->d.data->recipientInfo->encryptedData->encryptionAlgorithm->parameters->value.fullParams->iv = 
			AUTODISPOSE_OCTET_STRING;
	} else {
		ct->d.data->recipientInfo->encryptedData->encryptionAlgorithm->parameters->value.fullParams->iv = 
			AUTODISPOSE_IV;
