		recip = pinfo->cert;
		if (X509_cmp(recip, ct->d.data->recipientInfo->recipient) != 0)
			continue;

		/* We have the right recipient information, now we need to
		 * find the right recipient info type */
		if (ct->d.data->recipientInfo->type == CMS_RECIPINFO_SIMPLE) {
			ri = ct->d.data->recipientInfo;
			break;
