		cw[0] = word[0];
		cw[1] = word[i];
		cw[2] = NUL;
		word = cw;
		// Get the suggestions again.
		getspellitems(word, 2, SPELLGETSUGGEST);
		// Try to find a match.
		for (i = 0; i < g_s.spell_list_len && !did_complete; ++i)
		{
		    ps = &spell_items[i];
		    if (STRNICMP(ps->word, word, 2) == 0)	// found it!
			did_complete = TRUE;
		}
	    }
	    if (did_complete)
