     * This allows the  "using cached" short cut in the  debug functions.
     */
    conn->conn_data = *sessionid;

    /* We can't re-use the same session object for multiple connections so we
     * have to create a new one for each connect. This copies over the basic
     * information like type and key type but the ssl struct itself isn't used
     * anywhere else so it's ok.
