    sess = calloc(sizeof(struct Session), 1);
    if(sess) {
      sess->keytype = sid[0];
      sess->sessionid = sid;
      sess->sessionidlen = *len;
      sess->ssl = data->state.lastassocts->ssl;

      /* The copy above didn't copy over the back reference, set it here or
         we might get a leak later */
      sess->ssl->session = sess;

      LIST_ADDTAIL(sess, data->state.ssl_sessions);
      TRACE_MSG(data, TRACE_SSL, "Added %p (%" CURL_FORMAT_SIZE_T ") to "
                "session cache for %s", sess, sess->sessionidlen,
                conn->host.name);
    }
    else {
      TRACE_MSG(data, TRACE_SSL, "Out of memory when re-using SSL session "
                "ID for %s", conn->host.name);
      result = CURLE_OUT_OF_MEMORY;
    }
  }
  else if(data->state.ssl_sessions) {
    /* There's no current session to re-use so we go through the cache to
     * find a match.
