    struct Session *sess;
    LIST_FOREACH(sess, data->state.ssl_sessions) {
      if(sess->sessionidlen == conn->sslsessionid_len &&
         memcmp(sess->sessionid, conn->sslsessionid, conn->sslsessionid_len) ==
         0) {
        /* Found a match - now see if we can re-use it */
        *len = sess->sessionidlen;
        *sessionid = sess->sessionid;

        TRACE_MSG(data, TRACE_SSL, "Re-using cached SSL session ID of length %"
                  CURL_FORMAT_SIZE_T " for %s", *len, conn->host.name);

        /* Mark that we're using a session ID by setting the conn data pointer.
         * This allows the  "using cached" short cut in the  debug functions.
         */
        conn->conn_data = *sessionid;

        sess->count++;

        /* We can't re-use the same session object for multiple connections so
         * we have to create a new one for each connect. This copies over the
         * basic information like type and key type but the ssl struct itself
         * isn't used anywhere else so it's ok.
         */
        sess = calloc(sizeof(struct Session), 1);
        if(sess) {
          sess->keytype = conn->sslsessionid[0];
          sess->sessionid = *sessionid;
          sess->sessionidlen = *len;
          sess->ssl = data->state.lastassocts->ssl;

          /* The copy above didn't copy over the back reference, set it here
             or we might get a leak later */
          sess->ssl->session = sess;

          LIST_ADDTAIL(sess, data->state.ssl_sessions);
          TRACE_MSG(data, TRACE_SSL, "Added %p (%" CURL_FORMAT_SIZE_T ") to "
                    "session cache for %s", sess, sess->sessionidlen,
                    conn->host.name);
        }
        else {
          TRACE_MSG(data, TRACE_SSL, "Out of memory when re-using SSL session "
                    "ID for %s", conn->host.name);
          result = CURLE_OUT_OF_MEMORY;
        }

        break;
      }
    }
    if(sess == NULL) {
      TRACE_MSG(data, TRACE_SSL, "No cached SSL session ID found for %s",
                conn->host.name);
      (void)Curl_ssl_flush_sessions(data, NULL);
    }
  }
  else {
    TRACE_MSG(data, TRACE_SSL, "No SSL session cache to check for %s",
              conn->host.name);
  }

  return result;
