CURLcode Curl_ssl_connect_step2(struct connectdata *conn,
                                  int sockno,
                                  bool *afdohandshaked)
{
  CURLcode result = CURLE_OK;
  struct SessionHandle *data = conn->data;
  struct Session *ssl = data->state.proto.tls;
  int error;

  *afdohandshaked = FALSE;

  if(ssl->state == SSL_NOT_BUILT) {
    /* The ssl->slist->first may be NULL on SSL_NOT_BUILT so let's build a
     * new one */
    if(Curl_ssl_make_list(data, &ssl->slist, 0, NULL, NULL, conn->host.name)
       != CURLE_OK)
      return CURLE_SSL_CONNECT_ERROR;
    ssl->state = SSL_BUILT;
  }

  if(ssl->uses_slist) {
    /* This should be the common case */
    ssl->slist->first->connect_func(sockno, ssl->slist->first, &error);
  }
  else {
    /* This is the uncommon case where the application has provided their
     * own SSL setup callback which didn't pass a slist to us. In this
     * situation we know that the only SSL object on the list is the one
     * we want to talk to the server with. */
    ssl->slist->connect_func(sockno, ssl->slist->first, &error);
  }

  if(error) {
    failf(data, "SSL connect error (%d)", error);
    result = CURLE_SSL_CONNECT_ERROR;
  }
  else {
    /* The initial (and only) block of the select() timeout is spent in
       ssl_connect_step1(), the rest in ssl_connect_step2()s */

    /* Wait for the socket to become ready to read/write */
    struct timeval to = { 2, 0 }; /* 2 seconds */
    fd_set rdset, wrset;
    int rc;
    SOCKET skt = sockfd(sockno);

    FD_ZERO(&rdset);
    FD_ZERO(&wrset);
    FD_SET(skt, &rdset);
    FD_SET(skt, &wrset);

    rc = select(skt + 1, &rdset, &wrset, NULL, &to);

    if(rc < 0) {
      failf(data, "SSL select error: %s", strerror(errno));
      result = CURLE_SSL_CONNECT_ERROR;
    }
    else if(0 == rc) {
      /* This means that the timeout was hit */
      failf(data, "SSL connect timed out");
      result = CURLE_SSL_CONNECT_ERROR;
    }
    else {
      if(ssl->slist->read_func)
        ssl->slist->read_func(sockno, ssl->slist->first, &error);

      /* The read_func() may have closed the socket */
      if(data->state.os_errno)
        skt = CURL_SOCKET_BAD;

      if(error) {
        failf(data, "SSL connect error (%d)", error);
        result = CURLE_SSL_CONNECT_ERROR;
      }
      else {
        *afdohandshaked = TRUE;
        if(ssl->slist->write_func)
          ssl->slist->write_func(sockno, ssl->slist->first, &error);
        if(error) {
          failf(data, "SSL connect error (%d)", error);
          result = CURLE_SSL_CONNECT_ERROR;
        }
        else {
          /* The handshake is finished at this point */
          ssl->state = SSL_DONE;
          DEBUGF(fprintf(stderr, "SSL connection established\n"));
        }
      }

      /* In case the socket was closed we need to remove the file
         descriptor from the list ourselves */
      if(data->state.os_errno)
        Curl_ssl_cleanup_fd(data, skt);
    }
  }

  return result;
} /* Curl_ssl_connect_step2() */

