bool WindowsServiceControl::StopService() {
  SC_HANDLE hSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
  if (hSCManager == NULL) {
    PLOG(ERROR) << "OpenSCManager";
    return false;
  }

  SC_HANDLE hService = OpenService(hSCManager, name_.c_str(),
                                   SERVICE_ALL_ACCESS);
  if (hService == NULL) {
    PLOG(ERROR) << "OpenService " << name_;
    CloseServiceHandle(hSCManager);
    return false;
  }

  SERVICE_STATUS svc_status;
  if (!ControlService(hService, SERVICE_CONTROL_STOP, &svc_status)) {
    PLOG(ERROR) << "ControlService(STOP)";
    CloseServiceHandle(hSCManager);
    CloseServiceHandle(hService);
    return false;
  }

  int wait_millis = 0;
  const int kWaitSeconds = 30;
  while (wait_millis < kWaitSeconds * 1000) {
    if (QueryServiceStatus(hService, &svc_status) == FALSE) {
      PLOG(ERROR) << "QueryServiceStatus";
      break;
    }
    if (svc_status.dwCurrentState == SERVICE_STOPPED) {
      break;
    }
    Sleep(100);
    wait_millis += 100;
  }

  CloseServiceHandle(hSCManager);
  CloseServiceHandle(hService);
  return wait_millis < kWaitSeconds * 1000;
}

