        response_from_dbname_ns = true;
        mongo_append_string(&offset, query, "db", 3);
        mongo_append_string(&offset, query, auth_info->db_name, strlen(auth_info->db_name));
        mongo_append_string(&offset, query, "user", 4);
        mongo_append_string(&offset, query, auth_info->username, strlen(auth_info->username));
        if (auth_info->password != NULL)
            mongo_append_string(&offset, query, "password", 8);
        else
