    if (type == REDIS_REPLY_STATUS)
        return _redisReadString(reader, REDIS_ENCODING_RAW);
    if (type == REDIS_REPLY_INTEGER)
        return (void*)longlong_from_string(_redisReadString(reader, REDIS_ENCODING_RAW));
    if (type == REDIS_REPLY_NIL)
        return NULL;
    if (type == REDIS_REPLY_DOUBLE)
