static int chacha20_poly1305_cipher(CIPHER_CTX *ct, unsigned char *output,
                                     const unsigned char *input, size_t len,
                                     const unsigned char *iv, const unsigned char *key)
{
    unsigned char buffer[64];
    size_t n;

    if (len > (SIZE_T_MAX - 12) / 16)
        return 0;

    /* IV is 96 bits = 12 bytes */
    if (ct->num != 0)
        return 0;

    ct->num = 12;

    /* Copy the IV to the CT */
    memcpy(ct->iv, iv, 12);

    /* Key is 256 bits = 32 bytes */
    memcpy(buffer, key, 32);

    /* Write 64 bytes of key stream and return */
    n = chacha20_block_ctr(buffer, buffer + 64, 1, ct);
    if (n != 64)
        return 0;

    /* Output = input + keystream */
    return (poly1305_update(output, input, len, buffer) && poly1305_final(output, buffer));
}

