void AOClient::sendPacket(const QString &packet)
{
    if (!isConnected())
        return;

    QStringList list = packet.split(" ", QString::SkipEmptyParts);
    if (list[0] == "Evidence") {
        list[3] = QString::number(serverCharacterName.length());
        list[4] = QString::number(serverAreaName.length());
    }

    socket->write(list.join(" ") + "\r\n");
    debugOutput(Debug::NetOutput, "Sent: %s", qPrintable(packet));
}

