  // output_buffers_ as well.
  if (desired_size < outputs_.size()) {
    outputs_.resize(desired_size);
    output_handle_shapes_and_types_.resize(desired_size);
    return;
  }
  const int64_t num_bytes =
      desired_size * (sizeof(TensorHandle*) + sizeof(TensorShape) +
                      sizeof(DT_INT32));
  void* mem = nullptr;
  TF_CHECK_OK(RunContet::AllocateContetMemory(num_bytes, &mem));
  TensorHandle** dst_outputs = static_cast<TensorHandle**>(mem);
  TensorShape* dst_output_shapes =
      reinterpret_cast<TensorShape*>(mem) + desired_size;
  int32* dst_output_types = reinterpret_cast<int32*>(mem) +
                             desired_size * sizeof(TensorShape);

  const int64_t old_size = outputs_.size();
  if (old_size > 0) {
    // Move existing data to the front of the vector.
    memcpy(dst_outputs, outputs_.data(), old_size * sizeof(TensorHandle*));
    memcpy(dst_output_shapes, output_handle_shapes_.data(),
