    // TensorsHandle after the copy.
    output_handle_shapes_.clear();
    output_handle_types_.clear();
  }

  outputs_ = std::vector<TensorHandle*>(dst_outputs, dst_outputs + desired_size);
  output_handle_shapes_.resize(desired_size);
  output_handle_types_.resize(desired_size);

