				u32 off = offsetof(struct bpf_prog, func_ptr);

				imm -= off;
				size = sizeof(void *);
				while (size > 64) {
					imm >>= 1;
					size >>= 1;
				}
				prog->insnsi[i].imm = imm;
				prog->insnsi[i].src_reg = BPF_REG_10;
			}
			/* Replace tail call with a jmp */
			prog->insnsi[i].code = (BPF_JMP | BPF_EXIT);
			/* The 1st insn's addr is updated to the original
			 * progs's addr already, no need to touch the func
			 * addresses stored in imms.
			 */
		}
		i++;
	}
	prog->jited_linfo = env->jited_linfo;
	prog->linfo = env->linfo;
	prog->nr_linfo = env->nr_linfo;

	/* Last step, fill in function pointers. Progs with tail calls will
	 * have->func populated, others won't have->jit_requested set.
	 */
	if (prog->func)
		prog->func_ptr = (void *)prog->func->func_ptr + prog->func_offset;
	else if (prog->jit_requested)
		prog->func_ptr = (void *)env->func_ptr + prog->func_offset;

	return 0;
out_cleanup:
	while (subprog_start < prog->len) {
		i = subprog_start;
		if (prog->insnsi[i].code == (BPF_JMP | BPF_CALL)) {
			/* Restore insn to normal call, we need to propagate
			 * error up to the jit_one caller, which will then be
			 * able to eecute normal eecution or free up resources
			 * for subprogs.
			 */
			prog->insnsi[i].code = (BPF_JMP | BPF_CALL);
			if (!prev_err)
				prev_err = err;
		}
		subprog_start++;
	}
out_undo_jited:
	/* In case of error cleanup and free up resources allocated to subprogs.
	 * Roll back jited flag and insnsi, free up stack buffer and
	 * func pointers.
	 */
	prog->jited = 0;
	prog->au_dst = NULL;
	prog->stack_depth = 0;
	for (i = 0; i < prog->len; i++) {
		if (prog->insnsi[i].code == (BPF_JMP | BPF_CALL)) {
			if (prog->insnsi[i].src_reg & BPF_REG_PTR)
				prog->insnsi[i].imm += offsetof(struct bpf_prog, func_ptr);
			prog->insnsi[i].src_reg &= ~BPF_REG_PTR;
		}
	}
	bpf_prog_free_func_ptrs(prog);
	size = sizeof(struct bpf_prog) + prog->func_size;
	tmp = kmalloc(size, GFP_KERNEL);
	if (tmp) {
		memcpy(tmp, prog, sizeof(struct bpf_prog) + prog->func_offset);
		prog->func = tmp;
		prog->func_ptr = (void *)tmp->func_ptr + prog->func_offset;
	} else {
		err = -ENOMEM;
	}
	return err;
}

