spell_suggest_file(
    int		recent,		// TRUE for recent suggestions
    char_u	*filename)	// name of file to read from
{
    FILE *fp;
    int got_one = FALSE;	// TRUE when a match is found
    char_u line[MAXPATHL + 1 + MAXWORDL + 1 + 20]; // +1 for trail space
    char_u *p;

    fp = mch_fopen(filename, "r");
    if (fp == NULL)
	return -1;

    // Read one line at a time and check for a match.
    while (vim_fgets(line, MAXPATHL + 1 + MAXWORDL + 1 + 20, fp) != NULL)
    {
	// Allow trailing space in the preword so that spelling suggestions
	// can be loaded from a previous session.
	p = line + mb_strwidth(line);
	// Remove the suffix (score and probability).
	*p = * (p + 1) = * (p + 2) = NUL;
	// Ignore empty line or line that starts with a '#'.
	if (*line == NUL || *p == '#')
	{
	    got_one = FALSE;
	    continue;
	}
	if (spell_match_preword(line, recent))
	{
	    // Found a match: the suggestion file is sorted by frequency and
	    // probability, the first match is the most likely one.
	    if (!got_one)
	    {
		spell_suggest_from_line(line, TRUE, FALSE);
		got_one = TRUE;
	    }
	    else if (pedit.cmdline_off)
	    {
		out_string(_("Add another one? "));
		if (get_yes_no() == 'n')
		    break;
	    }
	    spell_suggest_from_line(line, FALSE, FALSE);
	}
    }
    mch_fclose(fp);
    if (!got_one)
	msg(_(e_no_suggestion_found));
    return 0;
}

